#!/usr/bin/env node
// Compiles src/tailwind.css via the Tailwind CLI and writes
// src/resources/tailwind-css.generated.ts, which the server serves at
// /static/tailwind.css the same way Alpine.js is vendored. Run via
// `npm run build:css`. The generated file is checked in so `npm run build`
// does not depend on the Tailwind CLI.
import { spawnSync } from "node:child_process";
import { readFileSync, writeFileSync, mkdirSync, rmSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { tmpdir } from "node:os";

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, "..");
const input = resolve(repoRoot, "src/tailwind.css");
const tmpOut = resolve(tmpdir(), `claws-tailwind-${process.pid}.css`);
const out = resolve(repoRoot, "src/resources/tailwind-css.generated.ts");

const result = spawnSync(
  "npx",
  ["@tailwindcss/cli", "-i", input, "-o", tmpOut, "--minify"],
  { cwd: repoRoot, stdio: "inherit" },
);
if (result.status !== 0) {
  process.exit(result.status ?? 1);
}

const css = readFileSync(tmpOut, "utf8");
rmSync(tmpOut, { force: true });

mkdirSync(dirname(out), { recursive: true });
const escaped = css.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
const header = "// Generated by scripts/build-tailwind.mjs — do not edit by hand.\n" +
  "// Run `npm run build:css` after changing markup so new Tailwind utility\n" +
  "// classes are picked up by the scanner in src/tailwind.css.\n";
writeFileSync(out, `${header}export const TAILWIND_CSS_SOURCE = \`${escaped}\`;\n`);
console.log(`Wrote ${out} (${css.length} bytes of CSS)`);
